import { GoogleGenAI, Type } from "@google/genai";

export interface GroundingLink {
  uri: string;
  title: string;
}

export const analyzeProcessData = async (
  nodeTitle: string, 
  rawText: string, 
  userPrompt: string, 
  location?: { latitude: number, longitude: number }
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const isMapsQuery = userPrompt.toLowerCase().includes('near') || 
                      userPrompt.toLowerCase().includes('map') || 
                      userPrompt.toLowerCase().includes('location');

  const modelName = isMapsQuery ? 'gemini-2.5-flash' : 'gemini-3-flash-preview';

  const systemInstruction = `You are a Process Intelligence Analyst. 
  Your task is to analyze process steps and provide structured, data-driven insights. 

  CRITICAL: You must calculate a "comparison_weight" (float, max 3.0) based on the following formula:
  weight = (number of pre-defined tasks in slots / number of instructions in your generated strategy) 
         + (number of resources identified in user data / total resources identified as needed) 
         + (number of tasks mentioned as 'done' or 'ready' in user notes / number of instructions in your generated strategy).

  Provide a summary of execution strategy and a list of required resources with estimated costs in USD (US Dollars).
  If external information is needed, use the Search tool. If geographic information is needed, use the Maps tool.`;

  const contents = `
    STEP TITLE: ${nodeTitle}
    CONTEXT DATA & USER NOTES: ${rawText}
    USER REQUEST: ${userPrompt}
  `;

  const tools: any[] = isMapsQuery ? [{ googleSearch: {} }, { googleMaps: {} }] : [{ googleSearch: {} }];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction,
        tools,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A detailed summary of the execution strategy." },
            comparison_weight: { type: Type.NUMBER, description: "The calculated alignment metric (max 3.0)." },
            resources: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  type: { type: Type.STRING },
                  cost: { type: Type.NUMBER, description: "Estimated cost in USD" },
                  available: { type: Type.BOOLEAN }
                },
                required: ["name", "type", "cost", "available"]
              }
            }
          },
          required: ["summary", "comparison_weight", "resources"]
        },
        toolConfig: location ? {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        } : undefined
      }
    });

    const jsonStr = response.text || '{}';
    const parsed = JSON.parse(jsonStr);

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links: GroundingLink[] = [];

    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        links.push({ uri: chunk.web.uri, title: chunk.web.title });
      } else if (chunk.maps) {
        links.push({ uri: chunk.maps.uri, title: chunk.maps.title });
      }
    });

    return {
      summary: parsed.summary,
      resources: parsed.resources,
      comparison_weight: parsed.comparison_weight,
      links: Array.from(new Set(links.map(l => JSON.stringify(l)))).map(s => JSON.parse(s)) as GroundingLink[]
    };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

export const generateGlobalStrategy = async (
  projectTitle: string,
  nodes: any[],
  connections: any[],
  insightsMap: Record<string, any>
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const nodeContext = nodes.map(n => {
    const ins = insightsMap[n.id];
    return `STEP: ${n.title}\nSTATUS: ${n.status}\nSUMMARY: ${ins?.summary || 'N/A'}\nWEIGHT: ${ins?.comparison_weight || 0}`;
  }).join('\n\n');

  const connectionContext = connections.map(c => `${c.sourceNodeId} -> ${c.targetNodeId} (${c.type})`).join('\n');

  const prompt = `Based on the provided process blueprint and individual node insights, generate a high-level "Full Execution Strategy" for ${projectTitle}.
  Account for the relationship connections (graph) between steps. 
  Address any failure points identified in nodes with status "failed".
  Format the response as professional markdown with sections for Objectives, Holistic Workflow, Risk Mitigation (based on failures), and Conclusion.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `PROJECT: ${projectTitle}\n\nCONNECTIONS:\n${connectionContext}\n\nNODES:\n${nodeContext}\n\n${prompt}`,
      config: { temperature: 0.7 }
    });
    return response.text;
  } catch (error) {
    console.error("Global Strategy Error:", error);
    return "Failed to synthesize global strategy. Please verify all milestones are synchronized.";
  }
};

import React, { useState, useCallback } from 'react';
import { PageView, ProcessNode, Connection, NodeInsights } from './types';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Insights from './components/Insights';
import Report from './components/Report';
import Simulation from './components/Simulation';

interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

const CURRENCIES = {
  USD: { symbol: '$', rate: 1, label: 'USD', name: 'US Dollar' },
  EUR: { symbol: '€', rate: 0.92, label: 'EUR', name: 'Euro' },
  GBP: { symbol: '£', rate: 0.79, label: 'GBP', name: 'British Pound' },
  JPY: { symbol: '¥', rate: 150.5, label: 'JPY', name: 'Japanese Yen' },
  INR: { symbol: '₹', rate: 83.2, label: 'INR', name: 'Indian Rupee' },
  CAD: { symbol: 'C$', rate: 1.35, label: 'CAD', name: 'Canadian Dollar' },
};

type CurrencyCode = keyof typeof CURRENCIES;

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>('editor');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [projectTitle, setProjectTitle] = useState('Process Strategy Master Plan');
  const [currency, setCurrency] = useState<CurrencyCode>('USD');

  const [nodes, setNodes] = useState<ProcessNode[]>([]);
  const [connections, setConnections] = useState<Connection[]>([]);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [insightsMap, setInsightsMap] = useState<Record<string, NodeInsights>>({});

  const [nodeDrafts, setNodeDrafts] = useState<Record<string, NodeDraft>>({});

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const formatCost = useCallback((amount: number) => {
    const { symbol, rate } = CURRENCIES[currency];
    const converted = amount * rate;
    return `${symbol}${converted.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;
  }, [currency]);

  const addNode = useCallback((x: number = 100, y: number = 100, layer: number = 0) => {
    const newNode: ProcessNode = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Process Step',
      description: 'Define the objectives for this specific task...',
      x,
      y,
      width: 240,
      height: 120,
      color: '#ffffff',
      slots: [
        { id: Math.random().toString(36).substr(2, 9), label: 'Primary Operation', type: 'task' }
      ],
      layer,
      status: 'idle'
    };
    setNodes(prev => [...prev, newNode]);
    setNodeDrafts(prev => ({ ...prev, [newNode.id]: { inputText: '', files: [], links: [] } }));
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<ProcessNode>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const deleteNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setConnections(prev => prev.filter(c => c.sourceNodeId !== id && c.targetNodeId !== id));
    setNodeDrafts(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    if (selectedNodeId === id) setSelectedNodeId(null);
  }, [selectedNodeId]);

  const addConnection = useCallback((conn: Connection) => {
    setConnections(prev => [...prev, conn]);
  }, []);

  const updateConnection = useCallback((id: string, updates: Partial<Connection>) => {
    setConnections(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  }, []);

  const deleteConnection = useCallback((id: string) => {
    setConnections(prev => prev.filter(c => c.id !== id));
  }, []);

  const renderPage = () => {
    switch (activePage) {
      case 'editor':
        return (
          <Editor 
            nodes={nodes} 
            connections={connections} 
            onAddNode={addNode} 
            onUpdateNode={updateNode} 
            onDeleteNode={deleteNode}
            onAddConnection={addConnection}
            onUpdateConnection={updateConnection}
            onDeleteConnection={deleteConnection}
            projectTitle={projectTitle}
            setProjectTitle={setProjectTitle}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
          />
        );
      case 'insights':
        return (
          <Insights 
            nodes={nodes}
            connections={connections}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
            insightsMap={insightsMap}
            setInsightsMap={setInsightsMap}
            nodeDrafts={nodeDrafts}
            setNodeDrafts={setNodeDrafts}
            formatCost={formatCost}
          />
        );
      case 'simulation':
        return (
          <Simulation 
            nodes={nodes} 
            connections={connections}
            insightsMap={insightsMap}
            nodeDrafts={nodeDrafts}
            setNodes={setNodes}
            formatCost={formatCost}
          />
        );
      case 'report':
        return (
          <Report 
            nodes={nodes} 
            connections={connections} 
            insightsMap={insightsMap}
            nodeDrafts={nodeDrafts}
            projectTitle={projectTitle}
            formatCost={formatCost}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={toggleSidebar} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <main className="flex-1 flex flex-col transition-all duration-300">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-40 shadow-sm">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleSidebar}
              className="p-2 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <svg className="w-6 h-6 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-br from-blue-700 to-indigo-700 bg-clip-text text-transparent tracking-tight">
              {projectTitle}
            </h1>
          </div>
          <div className="flex items-center gap-6">
             <div className="flex items-center gap-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wide">Currency</label>
                <select 
                  value={currency} 
                  onChange={(e) => setCurrency(e.target.value as CurrencyCode)}
                  className="bg-slate-50 border border-slate-200 rounded-lg px-2 py-1 text-sm font-bold text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  {Object.entries(CURRENCIES).map(([code, { label, symbol, name }]) => (
                    <option key={code} value={code}>{symbol} {label}</option>
                  ))}
                </select>
             </div>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-700 rounded-full text-xs font-bold border border-emerald-100 shadow-sm">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Live Sync
              </div>
              <div className="w-10 h-10 rounded-xl bg-slate-900 overflow-hidden border-2 border-white shadow-lg">
                <img src="https://picsum.photos/40/40?grayscale" alt="User profile" />
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 relative overflow-hidden bg-slate-100/50">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ProcessNode, NodeInsights, Connection, Resource } from '../types';
import { analyzeProcessData, GroundingLink } from '../services/geminiService';

interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

interface InsightsProps {
  nodes: ProcessNode[];
  connections: Connection[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
  nodeDrafts: Record<string, NodeDraft>;
  setNodeDrafts: React.Dispatch<React.SetStateAction<Record<string, NodeDraft>>>;
  formatCost: (amount: number) => string;
}

const Insights: React.FC<InsightsProps> = ({ 
  nodes, 
  connections,
  selectedNodeId, 
  setSelectedNodeId, 
  insightsMap, 
  setInsightsMap,
  nodeDrafts,
  setNodeDrafts,
  formatCost
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentLinks, setCurrentLinks] = useState<GroundingLink[]>([]);
  const [lastResponseText, setLastResponseText] = useState<string>('');
  const [linkInput, setLinkInput] = useState('');

  const currentNode = nodes.find(n => n.id === selectedNodeId);
  const currentDraft = selectedNodeId ? nodeDrafts[selectedNodeId] || { inputText: '', files: [], links: [] } : { inputText: '', files: [], links: [] };

  const updateDraftText = (text: string) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { ...prev[selectedNodeId], inputText: text }
    }));
  };

  const addLink = () => {
    if (!selectedNodeId || !linkInput.trim()) return;
    const url = linkInput.trim().startsWith('http') ? linkInput.trim() : `https://${linkInput.trim()}`;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { 
        ...prev[selectedNodeId], 
        links: [...(prev[selectedNodeId]?.links || []), url] 
      }
    }));
    setLinkInput('');
  };

  const removeLink = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        links: (prev[selectedNodeId]?.links || []).filter((_, i) => i !== index)
      }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && selectedNodeId) {
      const newFiles = Array.from(e.target.files);
      setNodeDrafts(prev => ({
        ...prev,
        [selectedNodeId]: { ...prev[selectedNodeId], files: [...prev[selectedNodeId].files, ...newFiles] }
      }));
    }
  };

  const removeFile = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        files: prev[selectedNodeId].files.filter((_, i) => i !== index)
      }
    }));
  };

  const handleAnalyze = async () => {
    if (!currentNode || !selectedNodeId) return;
    setIsAnalyzing(true);

    const upstreamConnections = connections.filter(c => c.targetNodeId === selectedNodeId);
    const dependencyContext = upstreamConnections.map(conn => {
      const sourceNode = nodes.find(n => n.id === conn.sourceNodeId);
      const sourceInsights = insightsMap[conn.sourceNodeId];
      return `
        DEPENDENCY FROM: ${sourceNode?.title || 'Unknown Step'}
        RELATIONSHIP TYPE: ${conn.type}
        SOURCE DESCRIPTION: ${sourceNode?.description || 'No description'}
        SOURCE REQUIREMENTS/OUTPUTS: ${sourceInsights?.summary || 'Not yet analyzed'}
      `;
    }).join('\n---\n');

    const fileContext = currentDraft.files.map(f => f.name).join(', ');
    const linkContext = (currentDraft.links || []).join(', ');
    const slotContext = currentNode.slots.map(s => `- ${s.label} (${s.type})`).join('\n');

    const rawContext = `
      TARGET NODE: ${currentNode.title}
      TARGET DESCRIPTION: ${currentNode.description}

      TARGET SLOTS (TASKS/OPS):
      ${slotContext || 'No specific task slots defined.'}

      RELATIONSHIP CONSTRAINTS (UPSTREAM DEPENDENCIES):
      ${dependencyContext || 'No direct upstream dependencies identified.'}

      SPECIFIC FILES PROVIDED: ${fileContext || 'None'}
      REFERENCE LINKS: ${linkContext || 'None'}
      USER NOTES: ${currentDraft.inputText}
    `;

    const prompt = `Analyze this process step. 
    1. Evaluate how the TARGET SLOTS (tasks/ops) fit into the execution strategy.
    2. Identify resources needed.
    3. Calculate the comparison_weight based on input data vs generated strategy.
    4. Ensure alignment with RELATIONAL CONSTRAINTS from predecessors.`;

    let location = undefined;
    try {
      if ('geolocation' in navigator) {
        const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
      }
    } catch (e) { console.debug("Location restricted"); }

    const result = await analyzeProcessData(currentNode.title, rawContext, prompt, location);

    if (result) {
      setLastResponseText(result.summary);
      setCurrentLinks(result.links);

      setInsightsMap(prev => ({
        ...prev,
        [selectedNodeId]: { 
          nodeId: selectedNodeId, 
          summary: result.summary, 
          requirements: ['High-bandwidth data link', 'Validation certificate'], // Can be derived or hardcoded for now
          resources: result.resources, 
          executionStyle: 'Standard Adaptive',
          links: result.links,
          comparison_weight: result.comparison_weight
        }
      }));
    }
    setIsAnalyzing(false);
  };

  const StepSelector = () => (
    <div className="flex items-center gap-3 bg-white border border-slate-200 rounded-xl px-4 py-2 shadow-sm">
      <label htmlFor="step-select" className="text-xs font-bold text-slate-400 uppercase tracking-tight">Active Node:</label>
      <select 
        id="step-select"
        value={selectedNodeId || ''}
        onChange={(e) => {
          setSelectedNodeId(e.target.value || null);
          setLastResponseText('');
          setCurrentLinks([]);
        }}
        className="bg-transparent text-sm font-bold text-slate-800 focus:outline-none cursor-pointer min-w-[200px]"
      >
        <option value="">-- Choose Target Node --</option>
        {nodes.map(node => (
          <option key={node.id} value={node.id}>
            {node.title || 'Untitled Step'}
          </option>
        ))}
      </select>
    </div>
  );

  if (!selectedNodeId && nodes.length > 0) {
    return (
      <div className="h-full flex flex-col p-6 space-y-6">
        <div className="flex items-center justify-between border-b pb-4">
           <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Process Intelligence</h2>
           <StepSelector />
        </div>
        <div className="flex-1 flex items-center justify-center text-slate-400 flex-col gap-4 bg-white rounded-2xl border border-dashed border-slate-200 shadow-inner">
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center border border-slate-100 mb-2">
            <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
          </div>
          <div className="text-center">
            <p className="text-lg font-bold text-slate-600">Select Step to Analyze</p>
            <p className="text-sm max-w-xs mx-auto">The system will automatically link upstream dependencies to ensure cross-process consistency.</p>
          </div>
        </div>
      </div>
    );
  }

  const currentInsights = selectedNodeId ? insightsMap[selectedNodeId] : null;

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-auto bg-slate-50/50">
      <div className="flex items-center justify-between border-b pb-4 sticky top-0 bg-white/80 backdrop-blur-md z-10 p-4 rounded-t-2xl">
        <div className="flex flex-col">
          <h2 className="text-2xl font-black text-slate-800 tracking-tighter uppercase">Intelligence Mapping</h2>
          <div className="flex items-center gap-2">
            <span className="text-[10px] bg-indigo-600 text-white px-2 py-0.5 rounded-full font-black uppercase">Active Pipeline</span>
            <p className="text-indigo-600 text-xs font-bold uppercase">{currentNode?.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <StepSelector />
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing || !selectedNodeId}
            className="px-8 py-3 bg-slate-900 text-white rounded-2xl font-black hover:bg-black disabled:opacity-50 flex items-center gap-3 transition-all shadow-xl active:scale-95 group"
          >
            {isAnalyzing ? (
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
            ) : (
              <>
                <svg className="w-5 h-5 text-indigo-400 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                DEEP ANALYSIS
              </>
            )}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pb-10 px-4">
        {/* Left Column: Data Input */}
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-[32px] border border-slate-200 shadow-sm space-y-8">
            <div className="flex justify-between items-center">
              <h3 className="font-bold flex items-center gap-3 text-slate-800 text-lg">
                <div className="w-10 h-10 rounded-2xl bg-indigo-50 flex items-center justify-center">
                  <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                </div>
                Step Data Assets
              </h3>
              <div className="flex items-center gap-2 px-3 py-1 bg-slate-50 border rounded-full">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Context Ready</span>
              </div>
            </div>

            {/* Tasks Preview */}
            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Active Task Slots</p>
              <div className="flex flex-wrap gap-2">
                {currentNode?.slots.map(slot => (
                  <span key={slot.id} className="px-3 py-1 bg-slate-50 border border-slate-200 rounded-lg text-xs font-bold text-slate-600 flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-indigo-400"></div>
                    {slot.label}
                  </span>
                ))}
                {currentNode?.slots.length === 0 && <span className="text-xs italic text-slate-400">No tasks defined in editor.</span>}
              </div>
            </div>

            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Process Notes & Requirements</p>
              <textarea 
                value={currentDraft.inputText}
