import React, { useState, useCallback, useRef } from 'react';
import { PageView, ProcessNode, Connection, NodeInsights } from './types';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Insights from './components/Insights';
import Report from './components/Report';
import Simulation from './components/Simulation';

interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

const CURRENCIES = {
  USD: { symbol: '$', rate: 1, label: 'USD', name: 'US Dollar' },
  EUR: { symbol: '€', rate: 0.92, label: 'EUR', name: 'Euro' },
  GBP: { symbol: '£', rate: 0.79, label: 'GBP', name: 'British Pound' },
  JPY: { symbol: '¥', rate: 150.5, label: 'JPY', name: 'Japanese Yen' },
  INR: { symbol: '₹', rate: 83.2, label: 'INR', name: 'Indian Rupee' },
  CAD: { symbol: 'C$', rate: 1.35, label: 'CAD', name: 'Canadian Dollar' },
};

type CurrencyCode = keyof typeof CURRENCIES;

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>('editor');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [projectTitle, setProjectTitle] = useState('Process Strategy Master Plan');
  const [currency, setCurrency] = useState<CurrencyCode>('USD');

  const [nodes, setNodes] = useState<ProcessNode[]>([]);
  const [connections, setConnections] = useState<Connection[]>([]);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [insightsMap, setInsightsMap] = useState<Record<string, NodeInsights>>({});

  const [nodeDrafts, setNodeDrafts] = useState<Record<string, NodeDraft>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const formatCost = useCallback((amount: number) => {
    const { symbol, rate } = CURRENCIES[currency];
    const converted = amount * rate;
    return `${symbol}${converted.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;
  }, [currency]);

  const saveProject = useCallback(() => {
    // Note: File objects in nodeDrafts cannot be serialized to JSON directly. 
    // We save the text, links, and insights.
    const projectData = {
      version: "1.0",
      timestamp: new Date().toISOString(),
      projectTitle,
      currency,
      nodes,
      connections,
      insightsMap,
      // We strip files from drafts as they are not serializable
      nodeDrafts: Object.entries(nodeDrafts).reduce((acc, [k, v]) => ({
        ...acc,
        [k]: { ...v, files: [] } 
      }), {})
    };

    const blob = new Blob([JSON.stringify(projectData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${projectTitle.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_data.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [projectTitle, currency, nodes, connections, insightsMap, nodeDrafts]);

  const loadProject = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // Basic validation
        if (data.version && data.nodes) {
          setProjectTitle(data.projectTitle || 'Untitled Project');
          setCurrency(data.currency || 'USD');
          setNodes(data.nodes || []);
          setConnections(data.connections || []);
          setInsightsMap(data.insightsMap || {});

          // Restore drafts, re-initializing files array as empty
          const restoredDrafts = (data.nodeDrafts || {});
          Object.keys(restoredDrafts).forEach(key => {
            restoredDrafts[key].files = [];
          });
          setNodeDrafts(restoredDrafts);

          alert('Project loaded successfully!');
        } else {
          throw new Error('Invalid project file format');
        }
      } catch (err) {
        console.error(err);
        alert('Failed to load project. Please check the file format.');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  }, []);

  const triggerLoad = () => fileInputRef.current?.click();

  const addNode = useCallback((x: number = 100, y: number = 100, layer: number = 0) => {
    const newNode: ProcessNode = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Process Step',
      description: 'Define the objectives for this specific task...',
      x,
      y,
      width: 240,
      height: 120,
      color: '#ffffff',
      slots: [
        { id: Math.random().toString(36).substr(2, 9), label: 'Primary Operation', type: 'task' }
      ],
      layer,
      status: 'idle'
    };
    setNodes(prev => [...prev, newNode]);
    setNodeDrafts(prev => ({ ...prev, [newNode.id]: { inputText: '', files: [], links: [] } }));
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<ProcessNode>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const deleteNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setConnections(prev => prev.filter(c => c.sourceNodeId !== id && c.targetNodeId !== id));
    setNodeDrafts(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    if (selectedNodeId === id) setSelectedNodeId(null);
  }, [selectedNodeId]);

  const addConnection = useCallback((conn: Connection) => {
    setConnections(prev => [...prev, conn]);
  }, []);

  const updateConnection = useCallback((id: string, updates: Partial<Connection>) => {
    setConnections(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  }, []);

  const deleteConnection = useCallback((id: string) => {
    setConnections(prev => prev.filter(c => c.id !== id));
  }, []);

  const renderPage = () => {
    switch (activePage) {
      case 'editor':
        return (
          <Editor 
            nodes={nodes} 
            connections={connections} 
            onAddNode={addNode} 
            onUpdateNode={updateNode} 
            onDeleteNode={deleteNode}
            onAddConnection={addConnection}
            onUpdateConnection={updateConnection}
            onDeleteConnection={deleteConnection}
            projectTitle={projectTitle}
            setProjectTitle={setProjectTitle}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
            onSaveProject={saveProject}
            onLoadProject={triggerLoad}
          />
        );
      case 'insights':
        return (
          <Insights 
            nodes={nodes}
            connections={connections}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
            insightsMap={insightsMap}
            setInsightsMap={setInsightsMap}
            nodeDrafts={nodeDrafts}
            setNodeDrafts={setNodeDrafts}
            formatCost={formatCost}
          />
        );
      case 'simulation':
        return (
          <Simulation 
            nodes={nodes} 
            connections={connections}
            insightsMap={insightsMap}
            nodeDrafts={nodeDrafts}
            setNodes={setNodes}
            formatCost={formatCost}
          />
        );
      case 'report':
        return (
          <Report 
            nodes={nodes} 
            connections={connections} 
            insightsMap={insightsMap}
            nodeDrafts={nodeDrafts}
            projectTitle={projectTitle}
            formatCost={formatCost}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={loadProject} 
        className="hidden" 
        accept=".json" 
      />

      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={toggleSidebar} 
        activePage={activePage} 
        setActivePage={setActivePage}
        onSaveProject={saveProject}
        onLoadProject={triggerLoad}
      />

      <main className="flex-1 flex flex-col transition-all duration-300">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-40 shadow-sm">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleSidebar}
              className="p-2 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <svg className="w-6 h-6 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-br from-blue-700 to-indigo-700 bg-clip-text text-transparent tracking-tight">
              {projectTitle}
            </h1>
          </div>
          <div className="flex items-center gap-6">
             <div className="flex items-center gap-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wide">Currency</label>
                <select 
                  value={currency} 
                  onChange={(e) => setCurrency(e.target.value as CurrencyCode)}
                  className="bg-slate-50 border border-slate-200 rounded-lg px-2 py-1 text-sm font-bold text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  {Object.entries(CURRENCIES).map(([code, { label, symbol, name }]) => (
                    <option key={code} value={code}>{symbol} {label}</option>
                  ))}
                </select>
             </div>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-700 rounded-full text-xs font-bold border border-emerald-100 shadow-sm">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                Live Sync
              </div>
              <div className="w-10 h-10 rounded-xl bg-slate-900 overflow-hidden border-2 border-white shadow-lg">
                <img src="https://picsum.photos/40/40?grayscale" alt="User profile" />
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 relative overflow-hidden bg-slate-100/50">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, SlotType, ConnectionType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x?: number, y?: number, layer?: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onDeleteNode: (id: string) => void;
  onAddConnection: (conn: Connection) => void;
  onUpdateConnection: (id: string, updates: Partial<Connection>) => void;
  onDeleteConnection: (id: string) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  onSaveProject: () => void;
  onLoadProject: () => void;
}

const COLORS = [
  { name: 'White', value: '#ffffff' },
  { name: 'Blue', value: '#eff6ff' },
  { name: 'Green', value: '#f0fdf4' },
  { name: 'Amber', value: '#fffbeb' },
  { name: 'Red', value: '#fef2f2' },
  { name: 'Slate', value: '#f8fafc' },
];

const CONNECTION_TYPES: { label: string, value: ConnectionType, color: string, dash?: string }[] = [
  { label: 'Dependency', value: 'dependency', color: '#64748b' },
  { label: 'Data Flow', value: 'data-flow', color: '#3b82f6' },
  { label: 'Resource Flow', value: 'resource-flow', color: '#10b981', dash: '5,5' },
  { label: 'Informational', value: 'informational', color: '#f59e0b', dash: '2,2' },
];

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onDeleteNode, onAddConnection, 
  onUpdateConnection, onDeleteConnection,
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId,
  onSaveProject, onLoadProject
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const [nodeContextMenu, setNodeContextMenu] = useState<{ x: number, y: number, nodeId: string } | null>(null);
  const [lineContextMenu, setLineContextMenu] = useState<{ x: number, y: number, connId: string } | null>(null);
  const [slotContextMenu, setSlotContextMenu] = useState<{ x: number, y: number, nodeId: string, slotId: string } | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const closeMenus = () => {
      setNodeContextMenu(null);
      setLineContextMenu(null);
      setSlotContextMenu(null);
    };
    window.addEventListener('click', closeMenus);
    return () => window.removeEventListener('click', closeMenus);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (draggingNodeId && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const scrollX = canvasRef.current.scrollLeft;
      const scrollY = canvasRef.current.scrollTop;
      const x = e.clientX - rect.left + scrollX - dragOffset.current.x;
      const y = e.clientY - rect.top + scrollY - dragOffset.current.y;
      const layer = Math.floor(y / 200);
      onUpdateNode(draggingNodeId, { x, y, layer });
    }
  }, [draggingNodeId, onUpdateNode]);

  const handleMouseUp = () => setDraggingNodeId(null);

  const handleNodeMouseDown = (e: React.MouseEvent, nodeId: string) => {
    if (e.button !== 0) return; 
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      setDraggingNodeId(nodeId);
      setSelectedNodeId(nodeId);
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleNodeContextMenu = (e: React.MouseEvent, nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setLineContextMenu(null);
    setSlotContextMenu(null);
    setNodeContextMenu({ x: e.clientX, y: e.clientY, nodeId });
  };

  const handleSlotContextMenu = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setLineContextMenu(null);
    setSlotContextMenu({ x: e.clientX, y: e.clientY, nodeId, slotId });
  };

  const handleLineContextMenu = (e: React.MouseEvent, connId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setSlotContextMenu(null);
    setLineContextMenu({ x: e.clientX, y: e.clientY, connId });
  };

  const handleSlotClick = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.stopPropagation();
    if (!isConnecting) {
      setIsConnecting({ nodeId, slotId });
    } else {
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false,
          type: 'dependency'
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  const deleteSlot = (nodeId: string, slotId: string) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      // 1. Remove connections involving this slot
      connections
        .filter(c => (c.sourceNodeId === nodeId && c.sourceSlotId === slotId) || (c.targetNodeId === nodeId && c.targetSlotId === slotId))
        .forEach(c => onDeleteConnection(c.id));

      // 2. Remove the slot from the node
      onUpdateNode(nodeId, {
        slots: node.slots.filter(s => s.id !== slotId)
      });
    }
    setSlotContextMenu(null);
  };

  const activeContextNode = nodes.find(n => n.id === nodeContextMenu?.nodeId);
  const activeContextConn = connections.find(c => c.id === lineContextMenu?.connId);

  // PRECISE UI DIMENSIONS FOR SLOT CENTER CALCULATION
  const HEADER_H = 37;
  const PADDING_T = 12; // from p-3
  const TEXTAREA_H = 48; // from h-12
  const GAP_S = 8; // from space-y-2
  const SLOT_H = 20; // from h-5
  const DOT_CENTER = 3; // vertical center of a 20px slot

  const BASE_Y_OFFSET = HEADER_H + PADDING_T + TEXTAREA_H + GAP_S + DOT_CENTER;

  return (
    <div className="flex flex-col h-full select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 border-r pr-4">
            <input 
              type="text" 
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
          </div>
          <div className="flex items-center gap-2">
