                      >
                        <div className={`w-1.5 h-1.5 rounded-full ${isConnecting?.slotId === slot.id ? 'bg-white' : 'bg-slate-300'}`}></div>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
